function u(t){const e=r((6-t.tappingSpeed)/5)*40,n=r((t.reactionTimeMs-250)/600)*25,o=r(t.intervalConsistency/400)*20,c=r(t.missedTaps/20)*15;return Math.round(e+n+o+c)}function h(t){const e=t.frequencyHz>=3.5&&t.frequencyHz<=7.5?1:.3,n=r(t.amplitude/1.5)*60*e,o=r(t.motionVariability/1)*40;return Math.round(Math.min(100,n+o))}function m(t){const e=r((3-t.rangeOfMotion)/3)*45,n=r((2-t.angularVelocity)/2)*25,o=r(1-t.smoothness)*30;return Math.round(e+n+o)}function d(t){const e=r((45-t.wpm)/40)*35,n=r(t.errorRate/.08)*25,o=r(t.intervalConsistency/300)*25,c=r(t.pauseCount/8)*15;return Math.round(Math.min(100,e+n+o+c))}function r(t){return Math.max(0,Math.min(1,t))}function f(t){return t.length?t.reduce((e,n)=>e+n,0)/t.length:0}function M(t){if(t.length<2)return 0;const e=f(t);return Math.sqrt(f(t.map(n=>(n-e)**2)))}function D(t,e){if(t.length<4||e<=0)return 0;const n=f(t);let o=0;for(let s=1;s<t.length;s++){const a=t[s-1]-n,i=t[s]-n;(a<0&&i>=0||a>0&&i<=0)&&o++}const c=t.length/e;return o/(2*c)}function l(t,e=25){const n=[];let o=0;const c=[];for(let s=0;s<t.length;s++)c.push(t[s]),o+=t[s],c.length>e&&(o-=c.shift()),n.push(t[s]-o/c.length);return n}function y(t){if(t.length<3)return 1;let e=0;for(let o=2;o<t.length;o++)e+=Math.abs(t[o]-2*t[o-1]+t[o-2]);const n=e/t.length;return Math.max(0,Math.min(1,1-n/2))}function v(t,e,n){return Math.sqrt(t*t+e*e+n*n)}export{D as a,u as b,f as c,l as d,M as e,d as f,v as m,m as r,y as s,h as t};
